+// ============================================================================
+// KV Cache Memory Management (Zero-Copy Sharing)
+// ============================================================================
+
+/// Get memory interface from context for KV cache operations
+pub fn getMemory(ctx: *const Context) c.llama_memory_t {
+    return c.llama_get_memory(ctx.handle);
+}
+
+/// Copy KV cache from one sequence to another (zero-copy)
+/// This enables sharing computed KV cache between cells without reprocessing
+///
+/// p0, p1: Position range to copy (-1 = all)
+/// - p0: Start position (-1 = from beginning)
+/// - p1: End position (-1 = to end)
+pub fn memoryCopySeq(
+    ctx: *const Context,
+    src_seq_id: i32,
+    dest_seq_id: i32,
+    p0: i32,
+    p1: i32,
+) void {
+    const mem: c.llama_memory_t = getMemory(ctx);
+    _ = c.llama_memory_seq_cp(mem, src_seq_id, dest_seq_id, p0, p1);
+}
+
+/// Remove KV cache entries for a sequence in the given position range
+pub fn memoryRemoveSeq(
+    ctx: *const Context,
+    seq_id: i32,
+    p0: i32,
+    p1: i32,
+) void {
+    const mem: c.llama_memory_t = getMemory(ctx);
+    _ = c.llama_memory_seq_rm(mem, seq_id, p0, p1);
+}
+
+/// Keep only the specified sequence, discard all others
+pub fn memoryKeepSeq(ctx: *const Context, seq_id: i32) void {
+    const mem: c.llama_memory_t = getMemory(ctx);
+    _ = c.llama_memory_seq_keep(mem, seq_id);
+}

