+const std = @import("std");
+
+/// Log levels in order of severity
+pub const LogLevel = enum {
+    debug,
+    info,
+    warn,
+    err,
+
+    pub fn fromString(s: []const u8) ?LogLevel {
+        if (std.mem.eql(u8, s, "debug")) return .debug;
+        if (std.mem.eql(u8, s, "info")) return .info;
+        if (std.mem.eql(u8, s, "warn")) return .warn;
+        if (std.mem.eql(u8, s, "error")) return .err;
+        return null;
+    }
+
+    pub fn toString(self: LogLevel) []const u8 {
+        return switch (self) {
+            .debug => "DEBUG",
+            .info => "INFO",
+            .warn => "WARN",
+            .err => "ERROR",
+        };
+    }
+};
+
+/// Structured logger with level filtering and optional file output
+pub const Logger = struct {
+    allocator: std.mem.Allocator,
+    log_file: ?std.fs.File,
+    level: LogLevel,
+    mutex: std.Thread.Mutex,
+
+    const Self = @This();
+
+    pub fn init(allocator: std.mem.Allocator, log_path: ?[]const u8, level: LogLevel) !Self {
+        const log_file = if (log_path) |path| blk: {
+            // Create log directory if it doesn't exist
+            if (std.fs.path.dirname(path)) |dir| {
+                std.fs.cwd().makePath(dir) catch |e| {
+                    if (e != error.PathAlreadyExists) return e;
+                };
+            }
+
+            // Open/create log file in append mode
+            break :blk try std.fs.cwd().createFile(path, .{
+                .truncate = false,
+                .read = false,
+            });
+        } else null;
+
+        return Self{
+            .allocator = allocator,
+            .log_file = log_file,
+            .level = level,
+            .mutex = .{},
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        if (self.log_file) |f| f.close();
+    }
+
+    /// Core logging function - thread-safe
+    pub fn log(self: *Self, level: LogLevel, comptime fmt: []const u8, args: anytype) void {
+        // Filter by level
+        if (@intFromEnum(level) < @intFromEnum(self.level)) return;
+
+        self.mutex.lock();
+        defer self.mutex.unlock();
+
+        // Get timestamp
+        const timestamp = std.time.timestamp();
+
+        // Format: [timestamp] LEVEL: message
+        const msg = std.fmt.allocPrint(
+            self.allocator,
+            "[{d}] {s}: " ++ fmt ++ "\n",
+            .{timestamp} ++ .{level.toString()} ++ args,
+        ) catch |e| {
+            // Fallback if allocation fails
+            std.debug.print("Logger allocation failed: {}\n", .{e});
+            return;
+        };
+        defer self.allocator.free(msg);
+
+        // Write to stderr
+        std.debug.print("{s}", .{msg});
+
+        // Write to file if enabled
+        if (self.log_file) |f| {
+            f.writeAll(msg) catch |e| {
+                std.debug.print("Failed to write to log file: {}\n", .{e});
+            };
+        }
+    }
+
+    pub fn debug(self: *Self, comptime fmt: []const u8, args: anytype) void {
+        self.log(.debug, fmt, args);
+    }
+
+    pub fn info(self: *Self, comptime fmt: []const u8, args: anytype) void {
+        self.log(.info, fmt, args);
+    }
+
+    pub fn warn(self: *Self, comptime fmt: []const u8, args: anytype) void {
+        self.log(.warn, fmt, args);
+    }
+
+    pub fn err(self: *Self, comptime fmt: []const u8, args: anytype) void {
+        self.log(.err, fmt, args);
+    }
+};
+
+// Global logger instance
+var global_logger: ?Logger = null;
+var global_mutex: std.Thread.Mutex = .{};
+
+/// Initialize global logger
+pub fn init(allocator: std.mem.Allocator, log_path: ?[]const u8, level: LogLevel) !void {
+    global_mutex.lock();
+    defer global_mutex.unlock();
+
+    if (global_logger != null) {
+        return error.AlreadyInitialized;
+    }
+
+    global_logger = try Logger.init(allocator, log_path, level);
+}
+
+/// Cleanup global logger
+pub fn deinit() void {
+    global_mutex.lock();
+    defer global_mutex.unlock();
+
+    if (global_logger) |*logger| {
+        logger.deinit();
+        global_logger = null;
+    }
+}
