+/// Run scheduler loop with real-time token streaming
+/// Returns total tokens generated across all cells
+fn runSchedulerLoop(
+    scheduler: *Scheduler,
+    max_iterations: u32,
+    on_token: ?*const fn ([]const u8) void,
+) !usize {
+    // Track output position for streaming (max 8 cells)
+    var cell_positions: [8]usize = [_]usize{0} ** 8;
+    var total_tokens: usize = 0;
+
+    var iterations: u32 = 0;
+    while (iterations < max_iterations) : (iterations += 1) {
+        const active = try scheduler.step();
+
+        // Stream new tokens from each cell
+        if (on_token) |callback| {
+            for (scheduler.cells, 0..) |*cell, i| {
+                if (cell.state == .completed or cell.state == .thinking) {
+                    const output = cell.getOutput();
+                    if (output.len > cell_positions[i]) {
+                        const new_output = output[cell_positions[i]..];
+                        if (new_output.len > 0) {
+                            callback(new_output);
+                            cell_positions[i] = output.len;
+                        }
+                    }
+                }
+            }
+        }
+
+        if (!active) break;
+    }
+
+    // Count total tokens generated
+    for (scheduler.cells) |cell| {
+        total_tokens += cell.generated_count;
+    }
+
+    return total_tokens;
+}
